{
  "domain_analysis": {
    "business_context": "Evolution of the Shipment aggregate from a 1:1 Shipment-Recipient relationship to a 1:N relationship. This is a fundamental change to the core domain model of a delivery platform, affecting the Shipment aggregate root boundary, all downstream processes (routing, labeling, proof-of-delivery, notifications), 2 million rows of production data, and external partner API contracts.",
    "bounded_context": "Shipment Management / Fulfillment",
    "ubiquitous_language": [
      { "term": "Shipment", "definition": "The aggregate root representing a single consignment moving through the delivery network from origin to one or more destinations." },
      { "term": "Recipient", "definition": "A value object or entity representing a person or entity receiving all or part of a Shipment. Has a name, address, phone number, and delivery preferences." },
      { "term": "Delivery Preference", "definition": "Recipient-specific instructions governing how delivery should be attempted — e.g., safe place, neighbour delivery, signature required, time window preference." },
      { "term": "Primary Recipient", "definition": "The first (or only) recipient on a shipment. For backward compatibility, legacy shipments have exactly one primary recipient." },
      { "term": "Multi-Recipient Shipment", "definition": "A shipment with two or more recipients, each potentially at different addresses with different delivery preferences." },
      { "term": "Delivery Attempt", "definition": "A single try to deliver to a specific recipient. In a multi-recipient shipment, each recipient has independent delivery attempts." },
      { "term": "Shipment Status", "definition": "The aggregate-level lifecycle state. Must now account for partial fulfillment when some recipients have been delivered and others have not." },
      { "term": "Partner API", "definition": "External integrations that consume shipment data in the current single-recipient format and must be migrated or adapted." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A Shipment MUST have at least one Recipient at all times.",
      "invariant": true,
      "invariant_justification": "A shipment with zero recipients is physically meaningless — there is no destination. This is a state-integrity constraint.",
      "testable_assertion": "Any attempt to create a Shipment with an empty recipient list, or to remove the last recipient from a Shipment, MUST be rejected."
    },
    {
      "id": "BR-2",
      "rule": "Each Recipient MUST have a valid name, address, and phone number.",
      "invariant": true,
      "invariant_justification": "These are the minimum data required for a courier to physically locate the destination and contact the recipient. Without them, delivery is impossible.",
      "testable_assertion": "Creating or updating a Recipient with a null/empty name, address, or phone number MUST be rejected at the aggregate boundary."
    },
    {
      "id": "BR-3",
      "rule": "Delivery preferences are scoped per-Recipient, not per-Shipment.",
      "invariant": true,
      "invariant_justification": "The entire purpose of multi-recipient support is that each recipient can have different delivery instructions. Collapsing preferences to shipment-level corrupts the model.",
      "testable_assertion": "Given a shipment with recipients A and B, setting delivery preference 'signature required' on A MUST NOT affect B's preferences."
    },
    {
      "id": "BR-4",
      "rule": "All 2 million existing single-recipient shipments MUST remain valid and queryable after migration with no data loss or semantic change.",
      "invariant": true,
      "invariant_justification": "Data integrity of production records is a hard constraint. Historical shipment data is used for billing, disputes, audit trails, and compliance.",
      "testable_assertion": "After migration, querying any pre-existing shipment MUST return the same recipient name, address, phone, and all associated delivery data as before migration."
    },
    {
      "id": "BR-5",
      "rule": "Shipment status must reflect the aggregate delivery state across ALL recipients.",
      "invariant": true,
      "invariant_justification": "A shipment cannot be marked 'delivered' if one of its recipients has not received their delivery. The status must be a correct projection of all recipient-level statuses.",
      "testable_assertion": "A shipment with 3 recipients where 2 are delivered and 1 is pending MUST NOT have aggregate status 'Delivered'. It must reflect partial fulfillment (e.g., 'Partially Delivered')."
    },
    {
      "id": "BR-6",
      "rule": "Each Recipient within a Shipment must be independently trackable.",
      "invariant": true,
      "invariant_justification": "Recipients at different addresses will have independent delivery attempts, ETAs, and proof-of-delivery events. Merging tracking defeats the purpose of multi-recipient support.",
      "testable_assertion": "Given a multi-recipient shipment, retrieving tracking events for Recipient A MUST return only events relevant to A, not events for Recipient B."
    },
    {
      "id": "BR-7",
      "rule": "Notifications (SMS, email) must be sent to each recipient based on their own delivery status and preferences, not the aggregate shipment status.",
      "invariant": false,
      "invariant_justification": "Notification behavior is a business policy. A VP could decide to batch-notify or change notification triggers. The core invariant is per-recipient tracking, not the notification policy itself.",
      "testable_assertion": "When Recipient A's delivery is completed but Recipient B's is still pending, Recipient A receives a 'delivered' notification while B does not."
    },
    {
      "id": "BR-8",
      "rule": "External partner APIs must continue to receive shipment data in a backward-compatible format during the transition period.",
      "invariant": false,
      "invariant_justification": "This is a migration policy, not a permanent physical constraint. Partners will eventually migrate to a new API version. The transition period is a business decision.",
      "testable_assertion": "Partner APIs that have not migrated to v2 MUST receive the primary recipient in the existing single-recipient payload format without breaking changes."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A new shipment is being created",
      "when": "The creator provides one or more recipients, each with name, address, phone, and optional delivery preferences",
      "then": "The shipment is created with all recipients attached, each with their own delivery preferences, and minimum one recipient is enforced"
    },
    {
      "id": "AC-2",
      "given": "An existing single-recipient shipment from the legacy dataset",
      "when": "The shipment is queried after migration",
      "then": "It returns with a recipients collection containing exactly one recipient, with all original data preserved including name, address, and phone number"
    },
    {
      "id": "AC-3",
      "given": "A multi-recipient shipment where Recipient A has been delivered",
      "when": "Recipient B's delivery is still pending",
      "then": "The shipment aggregate status is 'Partially Delivered', Recipient A's status is 'Delivered', and Recipient B's status is 'Pending'"
    },
    {
      "id": "AC-4",
      "given": "A multi-recipient shipment with recipients having different delivery preferences",
      "when": "A delivery attempt is made for one recipient",
      "then": "The courier sees only that recipient's delivery preferences (e.g., 'leave at door' vs 'signature required'), not preferences from other recipients"
    },
    {
      "id": "AC-5",
      "given": "An external partner API consumer that has not upgraded to the new API version",
      "when": "They request shipment data for a multi-recipient shipment",
      "then": "They receive a response in the legacy single-recipient format containing the primary recipient, and the response is structurally identical to pre-migration responses"
    },
    {
      "id": "AC-6",
      "given": "A user attempts to remove the last remaining recipient from a shipment",
      "when": "The removal request is processed",
      "then": "The system rejects the request with a clear error indicating a shipment must have at least one recipient"
    },
    {
      "id": "AC-7",
      "given": "A multi-recipient shipment where all recipients have been delivered",
      "when": "The last recipient delivery is confirmed",
      "then": "The shipment aggregate status transitions to 'Delivered' and all appropriate completion events are emitted"
    },
    {
      "id": "AC-8",
      "given": "A shipment with 2 million historical records in production",
      "when": "The data migration is executed",
      "then": "All records are migrated to the new schema with zero downtime or data loss, and rollback is possible within a defined window"
    }
  ],

  "edge_cases": [
    {
      "scenario": "Multi-recipient shipment where two recipients share the same address",
      "expected_behavior": "Both recipients are treated as distinct entities with independent tracking, delivery attempts, and preferences. The system must not deduplicate or merge them — they may be different people at the same location."
    },
    {
      "scenario": "Recipient is added to a shipment that is already in-transit",
      "expected_behavior": "Business must define whether this is allowed. If allowed, routing must be recalculated. If not, the request must be rejected with a clear reason referencing the shipment's current lifecycle state."
    },
    {
      "scenario": "One recipient in a multi-recipient shipment refuses delivery",
      "expected_behavior": "The refused recipient's status becomes 'Refused/Returned'. Other recipients are unaffected. The aggregate shipment status reflects partial completion. Return logistics are triggered only for the refused recipient's portion."
    },
    {
      "scenario": "Partner API receives a webhook for a multi-recipient shipment event but only understands single-recipient format",
      "expected_behavior": "The anti-corruption layer translates the event into the legacy format, mapping to the primary recipient. If the event is recipient-specific and pertains to a non-primary recipient, business must define whether it is suppressed or mapped."
    },
    {
      "scenario": "All recipients except one are delivered, and the remaining recipient's address is unreachable",
      "expected_behavior": "The shipment remains in 'Partially Delivered' state. Standard retry/return policies apply to the unreachable recipient independently. The shipment must never auto-complete to 'Delivered'."
    },
    {
      "scenario": "Billing and invoicing: a multi-recipient shipment may incur different costs per recipient (different zones, surcharges)",
      "expected_behavior": "Pricing must be calculated per-recipient-destination, not as a flat shipment rate. The billing bounded context must be updated to support itemized per-recipient charges."
    },
    {
      "scenario": "Reporting and analytics queries that assume 1:1 shipment-to-recipient",
      "expected_behavior": "All existing reports, dashboards, and data exports must be audited. Queries counting 'shipments delivered' must clarify whether they mean 'all recipients delivered' or 'at least one recipient delivered'."
    }
  ],

  "business_impact": {
    "financial": "Significant. Multi-recipient shipments could reduce per-unit delivery costs through route consolidation, increasing margin. However, billing systems must be updated to handle per-recipient pricing or risk revenue leakage. Migration costs (engineering, testing, partner coordination) are non-trivial. If partner APIs break, SLA penalties may apply.",
    "operational": "High complexity increase. Routing algorithms must optimize across multiple stops per shipment. Proof-of-delivery is now per-recipient. Warehouse pick/pack processes may change. Customer support must handle partial delivery inquiries. Status tracking dashboards need redesign. The 'Partially Delivered' state is net-new operational complexity that dispatchers and support teams must be trained on.",
    "user": "Positive for senders who ship to multiple recipients (e.g., corporate gifting, split orders). Recipients benefit from per-recipient delivery preferences. However, tracking UX must be redesigned — recipients should only see their own delivery status, not other recipients' data (privacy). Senders need a consolidated view.",
    "risk": "HIGH. This is a breaking change to the core domain model. Risks include: (1) data migration failure on 2M records, (2) partner API breakage causing integration failures, (3) billing discrepancies during transition, (4) reporting/analytics corruption from assumption changes, (5) privacy violations if recipient data leaks across recipients in a multi-recipient shipment. Rollback complexity is high once migration is deployed.",
    "stakeholders_affected": [
      { "group": "Senders/Shippers", "impact": "Gain ability to create multi-recipient shipments, reducing effort and potentially cost. Must learn new UI/API." },
      { "group": "Recipients", "impact": "Gain personalized delivery preferences. Privacy risk if multi-recipient data is not properly isolated." },
      { "group": "Couriers/Drivers", "impact": "Route plans change — a single shipment may now require multiple stops. Delivery app UI must show per-recipient instructions." },
      { "group": "External API Partners", "impact": "Breaking change if not handled via backward-compatible API versioning. Requires partner communication, migration guides, and a deprecation timeline." },
      { "group": "Customer Support", "impact": "Must handle new inquiry types: partial delivery, per-recipient issues, multi-recipient disputes. Training and tooling updates required." },
      { "group": "Finance/Billing", "impact": "Pricing model must evolve to per-recipient or per-stop. Invoicing, reconciliation, and dispute resolution all affected." },
      { "group": "Data/Analytics Team", "impact": "All shipment-level metrics must be re-evaluated. 'Delivery rate' definition changes. Historical comparisons may break without careful metric versioning." },
      { "group": "Operations/Dispatch", "impact": "Dispatch logic, SLA tracking, and capacity planning must account for multi-stop shipments." }
    ]
  },

  "confidence": {
    "level": 62,
    "reasoning": "The spec clearly defines the FROM and TO states of the model, which gives reasonable confidence on the core domain rules. However, several critical business decisions are unspecified: (1) what 'delivery preferences' actually includes is not enumerated, (2) whether recipients can be added/removed after shipment creation is undefined, (3) how billing adapts is unspecified, (4) the partner API migration strategy is only implied, not stated, and (5) the new shipment lifecycle states (e.g., 'Partially Delivered') are not defined in the spec. These gaps materially affect implementation correctness.",
    "high_confidence_areas": [
      "Core invariant: shipment must have >= 1 recipient",
      "Recipient data model: name, address, phone, preferences per-recipient",
      "Backward compatibility requirement for 2M existing records",
      "Partner API backward compatibility is needed"
    ],
    "low_confidence_areas": [
      "Exact definition and enumeration of 'delivery preferences'",
      "Shipment lifecycle state machine for multi-recipient (Partially Delivered, etc.)",
      "Whether recipients can be mutated after shipment enters transit",
      "Billing model changes",
      "Partner API deprecation timeline and versioning strategy",
      "Privacy rules around recipient data isolation within a shipment"
    ],
    "assumptions": [
      "The Shipment remains a single aggregate root containing a collection of Recipients, rather than splitting into separate aggregates",
      "Legacy shipments will be migrated to the new schema (recipients collection with one entry) rather than maintaining two schemas",
      "A 'primary recipient' concept exists for backward compatibility with partner APIs",
      "Delivery preferences are scoped per-recipient as stated, not shared at shipment level",
      "The existing 'Delivered' terminal status will be supplemented with a 'Partially Delivered' intermediate status"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec says 'delivery preferences' but does not enumerate what preferences are supported. This directly affects the Recipient value object schema, courier app UI, and notification logic. Examples could include: safe place, signature required, time window, neighbour delivery, authority to leave — but we are guessing.",
      "affected_stakeholders": ["Product Team", "Couriers/Drivers", "Recipients", "Engineering"],
      "options": [
        "A) Define a fixed enum of delivery preferences now",
        "B) Make delivery preferences a flexible key-value map extensible over time",
        "C) Start with a minimal set (e.g., signature required, safe place, time window) and iterate"
      ],
      "recommendation": "Option C — start with a well-defined minimal set based on the most common courier delivery options, and design the schema to be extensible."
    },
    {
      "type": "ambiguity",
      "description": "The shipment lifecycle state machine is not defined for multi-recipient scenarios. What are the valid aggregate states when recipients are in different individual states? Is 'Partially Delivered' a new state? What triggers final 'Delivered'?",
      "affected_stakeholders": ["Operations/Dispatch", "Customer Support", "Data/Analytics Team", "Engineering"],
      "options": [
        "A) Introduce 'Partially Delivered' as a new aggregate state between 'In Transit' and 'Delivered'",
        "B) Keep aggregate status as 'In Transit' until ALL recipients are delivered",
        "C) Remove aggregate status entirely and only track per-recipient status"
      ],
      "recommendation": "Option A — 'Partially Delivered' is the most operationally transparent state. It gives dispatchers and support agents clear visibility into multi-recipient progress."
    },
    {
      "type": "missing_context",
      "description": "No guidance on whether recipients can be added or removed from a shipment after creation, or after the shipment enters transit. This is a critical invariant decision that affects routing, billing, and the aggregate's consistency boundary.",
      "affected_stakeholders": ["Senders/Shippers", "Operations/Dispatch", "Couriers/Drivers", "Finance/Billing"],
      "options": [
        "A) Recipients are immutable after shipment creation",
        "B) Recipients can be modified until shipment enters transit, then frozen",
        "C) Recipients can be added/removed at any lifecycle stage with re-routing"
      ],
      "recommendation": "Option B — this mirrors standard logistics practice where manifests are finalized at dispatch. Allows flexibility during preparation while maintaining operational predictability."
    },
    {
      "type": "missing_context",
      "description": "Privacy implications of multi-recipient shipments are unaddressed. Can Recipient A see Recipient B's name, address, or delivery status? In B2C scenarios, recipients may be unrelated individuals. GDPR and similar regulations may apply.",
      "affected_stakeholders": ["Recipients", "Legal/Compliance", "Product Team", "Engineering"],
      "options": [
        "A) Full isolation — recipients cannot see each other's data",
        "B) Sender can see all recipients, but recipients can only see their own tracking",
        "C) All recipients can see shipment-level status but not other recipients' details"
      ],
      "recommendation": "Option B — sender has full visibility as the shipment creator, while recipient privacy is maintained. This aligns with GDPR data minimization principles."
    }
  ],

  "rejection_reasons": []
}

